// Budujemy zapytanie Overpass API dla POI w promieniu 5km
const geoData = $input.item.json;
const lat = parseFloat(geoData[0]?.lat || 52.2297);
const lon = parseFloat(geoData[0]?.lon || 21.0122);
const radius = 5000; // 5km

// Szukamy miejsc spacerowych: parki, fontanny, rzeźby, punkty widokowe, zamki
const query = `[out:json][timeout:25];
(
  node["leisure"="park"](around:${radius},${lat},${lon});
  node["amenity"="fountain"](around:${radius},${lat},${lon});
  node["tourism"="viewpoint"](around:${radius},${lat},${lon});
  node["tourism"="artwork"](around:${radius},${lat},${lon});
  node["historic"="castle"](around:${radius},${lat},${lon});
  node["historic"="monument"](around:${radius},${lat},${lon});
  node["tourism"="museum"](around:${radius},${lat},${lon});
  way["leisure"="park"](around:${radius},${lat},${lon});
  way["tourism"="attraction"](around:${radius},${lat},${lon});
);
out center body 40;`;

return [{ json: { query, centerLat: lat, centerLon: lon } }];

// ============================================
// FILTROWANIE POI + ALGORYTM KOMIWOJAZERA (TSP)
// Nearest Neighbor Heuristic
// ============================================

const overpassData = $('Overpass: Get POIs').item.json;
const buildData = $('Build Overpass Query').item.json;
const webhookBody = $('Webhook').item.json.body;

const centerLat = buildData.centerLat;
const centerLon = buildData.centerLon;

// --- Krok 1: Filtruj i zbieraj POI ---
const elements = overpassData.elements || [];
const allPOIs = [];

for (const el of elements) {
  const lat = el.lat || el.center?.lat;
  const lon = el.lon || el.center?.lon;
  const tags = el.tags || {};
  const name = tags.name || tags['name:pl'] || tags['name:en'];

  if (!lat || !lon || !name) continue;

  let priority = 1;
  // Najwyższy priorytet dla plenerów (spacery)
  if (tags.leisure === 'park') priority = 4;
  if (tags.amenity === 'fountain') priority = 4;
  if (tags.tourism === 'viewpoint') priority = 3;
  if (tags.tourism === 'artwork') priority = 3;
  if (tags.historic === 'castle') priority = 2;
  if (tags.historic === 'monument') priority = 2;
  // Muzea jako zapchajdziura, gdy brakuje innych punktów
  if (tags.tourism === 'museum') priority = 0;

  // Ukryj smutne pomniki historyczne z puli
  const nameLower = name.toLowerCase();
  const sadWords = ['powstań', 'poległ', 'walcząca', 'lotnika', 'ofiar', 'męczenni', 'katyń', 'cmentarz'];

  if (tags.historic === 'monument' && sadWords.some(w => nameLower.includes(w))) {
      priority = -1;
  }

  // DEDUPLIKACJA po nazwie
  const isDuplicate = allPOIs.some(p => p.name.toLowerCase() === nameLower);

  if (isDuplicate || priority === -1) continue;

  allPOIs.push({
    name,
    lat: parseFloat(lat),
    lon: parseFloat(lon),
    category: tags.leisure || tags.amenity || tags.historic || tags.tourism || 'atrakcja',
    description: tags.description || tags['description:pl'] || '',
    wikipedia: tags.wikipedia || '',
    priority
  });
}

// Posortuj po priorytecie i ogranicz do 8 najlepszych
allPOIs.sort((a, b) => b.priority - a.priority);
const topPOIs = allPOIs.slice(0, 8);

// Jezeli mamy za malo POI (< 2), zwroc blad
if (topPOIs.length < 2) {
  return [{ json: { error: 'Za malo punktow turystycznych znaleziono w tym miescie. Sprobuj wiekszego miasta.' } }];
}

// --- Krok 2: Algorytm Komiwojazera (Nearest Neighbor) ---
function haversine(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat/2)**2 +
    Math.cos(lat1 * Math.PI/180) * Math.cos(lat2 * Math.PI/180) * Math.sin(dLon/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

function nearestNeighborTSP(points) {
  const n = points.length;
  const visited = new Array(n).fill(false);
  const route = [0];
  visited[0] = true;

  for (let i = 1; i < n; i++) {
    const current = route[route.length - 1];
    let nearest = -1, minDist = Infinity;
    for (let j = 0; j < n; j++) {
      if (!visited[j]) {
        const d = haversine(points[current].lat, points[current].lon, points[j].lat, points[j].lon);
        if (d < minDist) { minDist = d; nearest = j; }
      }
    }
    visited[nearest] = true;
    route.push(nearest);
  }
  return route.map(i => points[i]);
}

const optimizedRoute = nearestNeighborTSP(topPOIs);

// Oblicz calkowity dystans trasy
let totalDistanceKm = 0;
for (let i = 0; i < optimizedRoute.length - 1; i++) {
  totalDistanceKm += haversine(
    optimizedRoute[i].lat, optimizedRoute[i].lon,
    optimizedRoute[i+1].lat, optimizedRoute[i+1].lon
  );
}

return [{
  json: {
    plannedRoute: optimizedRoute,
    totalSteps: optimizedRoute.length,
    totalDistanceKm: Math.round(totalDistanceKm * 10) / 10,
    centerLat,
    centerLon,
    city: webhookBody.city,
    ageGroup: webhookBody.ageGroup,
    sessionId: webhookBody.sessionId
  }
}];

const webhookData = $('Webhook').item.json.body;
const airtableRecord = $('Airtable: Check Session').item.json;
const isNewSession = !airtableRecord.id;

let plannedRoute = [];
let currentStepIndex = 0;
let totalSteps = 0;
let currentPOI = null;
let airtableId = airtableRecord.id;

if (isNewSession) {
  const tspData = $('TSP: Optimize Route').item.json;
  plannedRoute = tspData.plannedRoute || [];
  currentStepIndex = 0;
  totalSteps = tspData.totalSteps || 0;
  airtableId = $('Airtable: Create Session').item.json.id;
  currentPOI = plannedRoute[0] || null;
} else {
  const fields = airtableRecord.fields || {};
  try { plannedRoute = JSON.parse(fields.Planned_Route || '[]'); } catch(e) { plannedRoute = []; }
  currentStepIndex = parseInt(fields.Current_Step_Index || '0');
  totalSteps = parseInt(fields.Total_Steps || '0');
  currentPOI = plannedRoute[currentStepIndex] || null;
}

// Definiujemy style pisania dla różnych grup wiekowych
const agePrompts = {
  "3-6": "Pisz bardzo prosto, jak do 4-latka. Używaj radosnego tonu, personifikuj budynki i pomniki. Unikaj dat i trudnych nazw. Skup się na kolorach i liczeniu do 5.",
  "7-11": "Pisz jak do odkrywcy w wieku szkolnym. Dodawaj ciekawe legendy i zagadki logiczne.",
  "12+": "Pisz konkretnie, dodawaj fakty historyczne i trudniejsze wyzwania."
};

return [{
  json: {
    city: webhookData.city || "miasto",
    ageGroup: webhookData.ageGroup || "7-11",
    agePrompt: agePrompts[webhookData.ageGroup] || agePrompts["7-11"],
    plannedRoute: plannedRoute,
    currentStepIndex: currentStepIndex,
    totalSteps: totalSteps,
    currentPOI: currentPOI,
    airtableId: airtableId
  }
}];

const ctx = $('Prepare Context').item.json;
const item = $input.item.json;

// Jeśli Overpass nie znalazł punktów w tym mieście
if (ctx.error) return [{ json: { error: ctx.error } }];

let parsed = {
  narrative_text: 'Przepraszamy, system AI jest obecnie przeciążony...',
  updated_story_summary: 'Trasa zaplanowana, oczekiwanie na odblokowanie fabuły...',
  choices: [ { button_text: 'Przejdź do pierwszego punktu trasy', action_description: 'Rozpocznij', target_location: 'Kolejny punkt' } ]
};

// NOWE: Łapiemy tekst z każdej możliwej ścieżki, w tym z nowego węzła LangChain Gemini!
try {
  let rawText = '';
  if (typeof item.text === 'string') rawText = item.text;
  else if (item.content && item.content.parts) rawText = item.content.parts[0].text; // <--- TO NAPRAWIA PROBLEM!
  else if (item.candidates) rawText = item.candidates[0].content.parts[0].text;

  if (rawText) {
    const cleanText = rawText.replace(/```json\n?/gi, '').replace(/```\n?/gi, '').trim();
    parsed = JSON.parse(cleanText);
  }
} catch(e) {}

parsed.plannedRoute = ctx.plannedRoute || [];
parsed.currentStepIndex = ctx.currentStepIndex || 0;
parsed.totalSteps = ctx.totalSteps || (ctx.plannedRoute ? ctx.plannedRoute.length : 0);
parsed.currentPOI = ctx.currentPOI || (ctx.plannedRoute ? ctx.plannedRoute[0] : null);
parsed.city = ctx.city || "Wybrane miasto";

parsed.id = ctx.airtableId;
parsed.Story_Summary = parsed.updated_story_summary;
parsed.Current_Step_Index = parsed.currentStepIndex + 1;

return [{ json: parsed }];
